from dataclasses import dataclass
from enum import Enum

class ReviewTier(Enum):
    AUTO = "auto"        # deliver immediately
    QUEUE = "queue"      # standard human review queue
    ESCALATE = "escalate"  # SME or compliance review

@dataclass
class ConfidenceSignals:
    self_reported: float        # 0.0-1.0 from LLM self-assessment
    retrieval_coverage: float   # fraction of answer grounded in retrieved docs
    hedge_phrases_found: int    # count of uncertainty markers in output
    input_is_outlier: bool      # embedding distance from training distribution
    hard_rule_triggered: bool   # any rule-based flag fired

@dataclass
class RoutingDecision:
    tier: ReviewTier
    composite_score: float
    primary_reason: str

def compute_routing(signals: ConfidenceSignals, output_text: str) -> RoutingDecision:
    # Hard rules always escalate regardless of other signals
    if signals.hard_rule_triggered:
        return RoutingDecision(
            tier=ReviewTier.ESCALATE,
            composite_score=0.0,
            primary_reason="hard rule triggered (monetary threshold / legal keyword)",
        )

    score = (
        signals.self_reported * 0.35
        + signals.retrieval_coverage * 0.30
        + max(0.0, 1.0 - signals.hedge_phrases_found * 0.15) * 0.20
        + (0.0 if signals.input_is_outlier else 1.0) * 0.15
    )

    if score >= 0.80:
        tier = ReviewTier.AUTO
        reason = "high composite confidence"
    elif score >= 0.55:
        tier = ReviewTier.QUEUE
        reason = f"medium confidence ({score:.2f})"
    else:
        tier = ReviewTier.ESCALATE
        reason = f"low confidence ({score:.2f})"

    return RoutingDecision(tier=tier, composite_score=score, primary_reason=reason)

from dataclasses import dataclass, field
from datetime import datetime, timedelta
from enum import Enum
from typing import Optional

class Priority(Enum):
    P1 = 1   # 2h SLA — regulatory / time-sensitive
    P2 = 2   # 8h SLA — customer-facing
    P3 = 3   # 24h SLA — internal

@dataclass
class ReviewTask:
    task_id: str
    priority: Priority
    ai_output: str
    retrieved_context: list[str]
    confidence_score: float
    routing_reason: str
    created_at: datetime
    assigned_to: Optional[str] = None
    completed_at: Optional[datetime] = None
    reviewer_action: Optional[str] = None   # "approve", "edit", "reject"
    reviewer_correction: Optional[str] = None

    @property
    def sla_deadline(self) -> datetime:
        hours = {Priority.P1: 2, Priority.P2: 8, Priority.P3: 24}
        return self.created_at + timedelta(hours=hours[self.priority])

    @property
    def is_overdue(self) -> bool:
        return datetime.utcnow() > self.sla_deadline and self.completed_at is None

    def complete(self, action: str, correction: Optional[str] = None) -> None:
        self.reviewer_action = action
        self.reviewer_correction = correction
        self.completed_at = datetime.utcnow()

from dataclasses import dataclass
from datetime import datetime
from enum import Enum

class ReviewAction(Enum):
    APPROVE = "approve"          # AI output was correct; no change
    EDIT = "edit"                # AI output was mostly right; reviewer improved it
    REJECT = "reject"            # AI output was wrong; reviewer wrote replacement
    ESCALATE = "escalate"        # Reviewer lacks authority; send to SME

class RejectionCategory(Enum):
    FACTUAL_ERROR = "factual_error"
    POLICY_VIOLATION = "policy_violation"
    MISSING_INFORMATION = "missing_information"
    TONE = "tone"
    HALLUCINATED_CITATION = "hallucinated_citation"
    REGULATORY_NONCOMPLIANCE = "regulatory_noncompliance"

@dataclass
class ReviewFeedback:
    task_id: str
    reviewer_id: str
    action: ReviewAction
    ai_output: str
    final_output: str           # what was actually delivered to the user
    rejection_category: RejectionCategory | None
    rejection_note: str
    review_duration_seconds: int
    timestamp: datetime

    @property
    def is_correction(self) -> bool:
        return self.action in (ReviewAction.EDIT, ReviewAction.REJECT)

    @property
    def correction_diff(self) -> tuple[str, str] | None:
        if self.is_correction:
            return (self.ai_output, self.final_output)
        return None

def store_feedback(feedback: ReviewFeedback, feedback_store) -> None:
    feedback_store.write({
        "task_id": feedback.task_id,
        "action": feedback.action.value,
        "ai_output": feedback.ai_output,
        "final_output": feedback.final_output,
        "rejection_category": feedback.rejection_category.value if feedback.rejection_category else None,
        "is_correction": feedback.is_correction,
        "review_duration_s": feedback.review_duration_seconds,
        "timestamp": feedback.timestamp.isoformat(),
    })
