from dataclasses import dataclass
from typing import Optional

@dataclass
class HITLGate:
    gate_id: str
    routing_fn: callable  # returns ReviewTier given output + signals
    queue: object         # task queue to enqueue to
    timeout_seconds: int  # how long to wait for human decision

    async def apply(self, output: str, signals: ConfidenceSignals, context: dict) -> str:
        decision = self.routing_fn(signals, output)
        if decision.tier.value == "auto":
            return output  # pass through immediately

        task = ReviewTask(
            task_id=generate_task_id(),
            priority=map_tier_to_priority(decision.tier),
            ai_output=output,
            retrieved_context=context.get("chunks", []),
            confidence_score=decision.composite_score,
            routing_reason=decision.primary_reason,
            created_at=datetime.utcnow(),
        )
        await self.queue.enqueue(task)

        # Await human decision (async blocking with timeout)
        result = await self.queue.await_decision(task.task_id, timeout=self.timeout_seconds)
        if result is None:
            raise TimeoutError(f"HITL gate {self.gate_id} timed out after {self.timeout_seconds}s")

        return result.final_output

def generate_task_id() -> str:
    import uuid
    return str(uuid.uuid4())

def map_tier_to_priority(tier) -> Priority:
    mapping = {ReviewTier.QUEUE: Priority.P2, ReviewTier.ESCALATE: Priority.P1}
    return mapping.get(tier, Priority.P3)
